<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Services\ReportService;use Illuminate\Http\Request;
class ReportController extends Controller{use Concerns;public function index(){return view('tenant.reports.index');}private function show(Request $r,ReportService $s,string $view,string $method){$this->requirePerm('tenant.reports.view');return view($view,['rows'=>$s->$method($r->all()),'filters'=>$r->all()]);}public function taskStatus(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.task-status','taskStatusReport');}public function overdueTasks(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.overdue-tasks','overdueTaskReport');}public function noUpdateTasks(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.no-update-tasks','noUpdateTaskReport');}public function proofPending(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.proof-pending','proofPendingReport');}public function approvalPending(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.approval-pending','approvalPendingReport');}public function dailySubmissions(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.daily-submissions','dailyReportSubmissionReport');}public function missingReports(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.missing-reports','missingReportReport');}public function employeePerformance(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.employee-performance','employeePerformanceReport');}public function teamPerformance(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.team-performance','teamPerformanceReport');}public function aiWeeklySummary(Request $r,ReportService $s){return $this->show($r,$s,'tenant.reports.ai-weekly-summary','aiWeeklySummaryReport');}}
